-- ============================================================
-- test_all_field_type_table
-- 目的：测试迁移中心任务，覆盖 MySQL 所有常见字段类型
-- 数据库：test_migration (Docker MySQL)
-- 数据量：100 条
-- ============================================================

DROP TABLE IF EXISTS `test_all_field_type_table`;

CREATE TABLE `test_all_field_type_table` (
    -- 整数类型
    `id`              INT AUTO_INCREMENT PRIMARY KEY,
    `c_tinyint`       TINYINT,
    `c_smallint`      SMALLINT,
    `c_mediumint`     MEDIUMINT,
    `c_int`           INT,
    `c_bigint`        BIGINT,
    `c_tinyint_1`     TINYINT(1),          -- 常被用作布尔值
    `c_unsigned_int`  INT UNSIGNED,

    -- 浮点/定点类型
    `c_float`         FLOAT,
    `c_double`        DOUBLE,
    `c_decimal`       DECIMAL(10, 4),
    `c_numeric`       NUMERIC(8, 2),

    -- 字符串类型
    `c_char`          CHAR(10),
    `c_varchar`       VARCHAR(100),
    `c_tinytext`      TINYTEXT,
    `c_text`          TEXT,
    `c_mediumtext`    MEDIUMTEXT,
    `c_longtext`      LONGTEXT,

    -- 二进制类型
    `c_binary`        BINARY(16),
    `c_varbinary`     VARBINARY(100),
    `c_blob`          BLOB,
    `c_tinyblob`      TINYBLOB,
    `c_mediumblob`    MEDIUMBLOB,
    `c_longblob`      LONGBLOB,

    -- 日期时间类型
    `c_date`          DATE,
    `c_time`          TIME,
    `c_datetime`      DATETIME,
    `c_timestamp`     TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    `c_year`          YEAR,

    -- JSON 类型 (MySQL 5.7+)
    `c_json`          JSON,

    -- ENUM / SET 类型
    `c_enum`          ENUM('pending', 'active', 'suspended', 'deleted'),
    `c_set`           SET('red', 'green', 'blue', 'yellow'),

    -- BIT 类型
    `c_bit`           BIT(8),

    -- 可空字段（专门测试 NULL 处理）
    `c_nullable_int`  INT DEFAULT NULL,
    `c_nullable_str`  VARCHAR(50) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

